    Version(context.Context, *VersionRequest) (*VersionResponse, error)
    RunPodSandbox(context.Context, *RunPodSandboxRequest) (*RunPodSandboxResponse, error)
    StopPodSandbox(context.Context, *StopPodSandboxRequest) (*StopPodSandboxResponse, error)
    RemovePodSandbox(context.Context, *RemovePodSandboxRequest) (*RemovePodSandboxResponse, error)
    PodSandboxStatus(context.Context, *PodSandboxStatusRequest) (*PodSandboxStatusResponse, error)
    ListPodSandbox(context.Context, *ListPodSandboxRequest) (*ListPodSandboxResponse, error)
    CreateContainer(context.Context, *CreateContainerRequest) (*CreateContainerResponse, error)
    StartContainer(context.Context, *StartContainerRequest) (*StartContainerResponse, error)
    StopContainer(context.Context, *StopContainerRequest) (*StopContainerResponse, error)
    RemoveContainer(context.Context, *RemoveContainerRequest) (*RemoveContainerResponse, error)
    ListContainers(context.Context, *ListContainersRequest) (*ListContainersResponse, error)
    ContainerStatus(context.Context, *ContainerStatusRequest) (*ContainerStatusResponse, error)
    UpdateContainerResources(context.Context, *UpdateContainerResourcesRequest) (*UpdateContainerResourcesResponse, error)
    ReopenContainerLog(context.Context, *ReopenContainerLogRequest) (*ReopenContainerLogResponse, error)
    ExecSync(context.Context, *ExecSyncRequest) (*ExecSyncResponse, error)
    Exec(context.Context, *ExecRequest) (*ExecResponse, error)
    Attach(context.Context, *AttachRequest) (*AttachResponse, error)
    PortForward(context.Context, *PortForwardRequest) (*PortForwardResponse, error)
    ContainerStats(context.Context, *ContainerStatsRequest) (*ContainerStatsResponse, error)
    ListContainerStats(context.Context, *ListContainerStatsRequest) (*ListContainerStatsResponse, error)
    PodSandboxStats(context.Context, *PodSandboxStatsRequest) (*PodSandboxStats, error)
    ListPodSandboxStats(context.Context, *ListPodSandboxStatsRequest) (*ListPodSandboxStatsResponse, error)
    UpdateRuntimeConfig(context.Context, *UpdateRuntimeConfigRequest) (*UpdateRuntimeConfigResponse, error)
    Status(context.Context, *StatusRequest) (*StatusResponse, error)
    CheckpointContainer(context.Context, *CheckpointContainerRequest) (*CheckpointContainerResponse, error)
    GetContainerEvents(*GetEventsRequest, grpc.ServerStreamingServer[ContainerEventResponse]) error
    ListMetricDescriptors(context.Context, *ListMetricDescriptorsRequest) (*ListMetricDescriptorsResponse, error)
    ListPodSandboxMetrics(context.Context, *ListPodSandboxMetricsRequest) (*ListPodSandboxMetricsResponse, error)
    RuntimeConfig(context.Context, *RuntimeConfigRequest) (*RuntimeConfigResponse, error)
    UpdatePodSandboxResources(context.Context, *UpdatePodSandboxResourcesRequest) (*UpdatePodSandboxResourcesResponse, error)
    mustEmbedUnimplementedRuntimeServiceServer()
}
```

---

## Part 2: Kubernetes Go API Interfaces

### Location
- **Path:** `staging/src/k8s.io/cri-api/pkg/apis/services.go`

### Purpose
While the gRPC interface defines the wire protocol, Kubernetes also defines higher-level Go interfaces for internal use. These interfaces break down the functionality into smaller, more manageable chunks:

### Main Interfaces

1. **RuntimeVersioner**
   - `Version(ctx context.Context, apiVersion string) (*runtimeapi.VersionResponse, error)`

2. **PodSandboxManager**
   - `RunPodSandbox(ctx context.Context, config *runtimeapi.PodSandboxConfig, runtimeHandler string) (string, error)`
   - `StopPodSandbox(ctx context.Context, podSandboxID string) error`
   - `RemovePodSandbox(ctx context.Context, podSandboxID string) error`
   - `PodSandboxStatus(ctx context.Context, podSandboxID string, verbose bool) (*runtimeapi.PodSandboxStatusResponse, error)`
   - `ListPodSandbox(ctx context.Context, filter *runtimeapi.PodSandboxFilter) ([]*runtimeapi.PodSandbox, error)`
   - `PortForward(ctx context.Context, request *runtimeapi.PortForwardRequest) (*runtimeapi.PortForwardResponse, error)`
   - `UpdatePodSandboxResources(ctx context.Context, request *runtimeapi.UpdatePodSandboxResourcesRequest) (*runtimeapi.UpdatePodSandboxResourcesResponse, error)`

3. **ContainerManager**
   - `CreateContainer(ctx context.Context, podSandboxID string, config *runtimeapi.ContainerConfig, sandboxConfig *runtimeapi.PodSandboxConfig) (string, error)`
   - `StartContainer(ctx context.Context, containerID string) error`
   - `StopContainer(ctx context.Context, containerID string, timeout int64) error`
   - `RemoveContainer(ctx context.Context, containerID string) error`
   - `ListContainers(ctx context.Context, filter *runtimeapi.ContainerFilter) ([]*runtimeapi.Container, error)`
   - `ContainerStatus(ctx context.Context, containerID string, verbose bool) (*runtimeapi.ContainerStatusResponse, error)`
   - `UpdateContainerResources(ctx context.Context, containerID string, resources *runtimeapi.ContainerResources) error`
   - `ExecSync(ctx context.Context, containerID string, cmd []string, timeout time.Duration) (stdout []byte, stderr []byte, err error)`
   - `Exec(ctx context.Context, request *runtimeapi.ExecRequest) (*runtimeapi.ExecResponse, error)`
   - `Attach(ctx context.Context, req *runtimeapi.AttachRequest) (*runtimeapi.AttachResponse, error)`
   - `ReopenContainerLog(ctx context.Context, ContainerID string) error`
   - `CheckpointContainer(ctx context.Context, options *runtimeapi.CheckpointContainerRequest) error`
   - `GetContainerEvents(ctx context.Context, containerEventsCh chan *runtimeapi.ContainerEventResponse, connectionEstablishedCallback func(runtimeapi.RuntimeService_GetContainerEventsClient)) error`

4. **ContainerStatsManager**
   - `ContainerStats(ctx context.Context, containerID string) (*runtimeapi.ContainerStats, error)`
   - `ListContainerStats(ctx context.Context, filter *runtimeapi.ContainerStatsFilter) ([]*runtimeapi.ContainerStats, error)`
   - `PodSandboxStats(ctx context.Context, podSandboxID string) (*runtimeapi.PodSandboxStats, error)`
   - `ListPodSandboxStats(ctx context.Context, filter *runtimeapi.PodSandboxStatsFilter) ([]*runtimeapi.PodSandboxStats, error)`
   - `ListMetricDescriptors(ctx context.Context) ([]*runtimeapi.MetricDescriptor, error)`
   - `ListPodSandboxMetrics(ctx context.Context) ([]*runtimeapi.PodSandboxMetrics, error)`

5. **RuntimeService** (Composite Interface)
   - Combines: RuntimeVersioner, ContainerManager, PodSandboxManager, ContainerStatsManager
   - Additional methods:
     - `UpdateRuntimeConfig(ctx context.Context, runtimeConfig *runtimeapi.RuntimeConfig) error`
     - `Status(ctx context.Context, verbose bool) (*runtimeapi.StatusResponse, error)`
     - `RuntimeConfig(ctx context.Context) (*runtimeapi.RuntimeConfigResponse, error)`
     - `Close() error`

6. **ImageManagerService**
   - `ListImages(ctx context.Context, filter *runtimeapi.ImageFilter) ([]*runtimeapi.Image, error)`
   - `ImageStatus(ctx context.Context, image *runtimeapi.ImageSpec, verbose bool) (*runtimeapi.ImageStatusResponse, error)`
   - `PullImage(ctx context.Context, image *runtimeapi.ImageSpec, auth *runtimeapi.AuthConfig, podSandboxConfig *runtimeapi.PodSandboxConfig) (string, error)`
   - `RemoveImage(ctx context.Context, image *runtimeapi.ImageSpec) error`
   - `ImageFsInfo(ctx context.Context) (*runtimeapi.ImageFsInfoResponse, error)`
   - `Close() error`

---

## Part 3: containerd's CRI Implementation

### Location
- **Repository:** `github.com/sg-evals/containerd--317286ac`
- **Main Paths:**
  - `plugins/cri/` - Plugin registration and setup
  - `internal/cri/server/` - Core CRI service implementation
  - `internal/cri/instrument/` - Instrumentation and metrics
  - `vendor/k8s.io/cri-api/` - Vendored Kubernetes CRI API types

### Architecture Overview

containerd implements the CRI interface through a multi-layered architecture:

```
┌─────────────────────────────────────────────────────────┐
│ gRPC Server (grpc.Server)                               │
│ ┌─────────────────────────────────────────────────────┐ │
│ │ criGRPCServer (runtime.RuntimeServiceServer impl)   │ │
│ └─────────────────────────────────────────────────────┘ │
└─────────────────────┬───────────────────────────────────┘
                      │
        ┌─────────────▼──────────────┐
        │  instrument.NewService()   │
        │ (instrumented wrapper)     │
        └─────────────┬──────────────┘
                      │
        ┌─────────────▼──────────────────┐
        │ criService struct              │
        │ (main implementation)          │
        └─────────────┬──────────────────┘
                      │
    ┌─────────────────┼─────────────────┐
    │                 │                 │
    ▼                 ▼                 ▼
Sandbox Ops      Container Ops    Image/Stats Ops
```

### 3.1 Plugin Registration & Initialization

**File:** `plugins/cri/cri.go`

```go
// Registration entry point
func init() {
    defaultConfig := criconfig.DefaultServerConfig()
    registry.Register(&plugin.Registration{
        Type: plugins.GRPCPlugin,
        ID:   "cri",
        Requires: []plugin.Type{
            plugins.CRIServicePlugin,       // Runtime service
            plugins.PodSandboxPlugin,       // Pod sandbox support
            plugins.SandboxControllerPlugin, // Sandbox controllers
            plugins.NRIApiPlugin,           // Node Resource Interface
            plugins.EventPlugin,            // Event handling
            plugins.ServicePlugin,          // Services
            plugins.LeasePlugin,            // Lease management
            plugins.SandboxStorePlugin,     // Sandbox storage
            plugins.TransferPlugin,         // Content transfer
            plugins.WarningPlugin,          // Warning service
        },
        ConfigMigration: configMigration,
        InitFn:          initCRIService,
    })
}

// Initialization function
func initCRIService(ic *plugin.InitContext) (interface{}, error) {
    // 1. Load runtime service plugin
    criRuntimePlugin, err := ic.GetByID(plugins.CRIServicePlugin, "runtime")

    // 2. Load image service plugin
    criImagePlugin, err := ic.GetByID(plugins.CRIServicePlugin, "images")

    // 3. Create containerd client
    client, err := containerd.New("",
        containerd.WithDefaultNamespace(constants.K8sContainerdNamespace),
        containerd.WithDefaultPlatform(platforms.Default()),
        containerd.WithInMemoryServices(ic),
    )

    // 4. Get sandbox controllers
    sbControllers, err := getSandboxControllers(ic)

    // 5. Create CRI service
    s, rs, err := server.NewCRIService(&server.CRIServiceOptions{
        RuntimeService:     criRuntimePlugin.(server.RuntimeService),
        ImageService:       criImagePlugin.(server.ImageService),
        StreamingConfig:    streamingConfig,
        NRI:                getNRIAPI(ic),
        Client:             client,
        SandboxControllers: sbControllers,
    })

    // 6. Wrap in gRPC server
    service := &criGRPCServer{
        RuntimeServiceServer: rs,
        ImageServiceServer:   is,
        Closer:               s,
        initializer:          s,
    }

    return service, nil
}
```

### 3.2 Core CRI Service Implementation

**File:** `internal/cri/server/service.go`

The `criService` struct implements the core logic:

```go
type criService struct {
    // Embedded unimplemented server to satisfy gRPC requirements
    runtime.UnimplementedRuntimeServiceServer
    runtime.UnimplementedImageServiceServer

    // Service dependencies
    RuntimeService
    ImageService

    // Configuration
    config criconfig.Config
    imageFSPaths map[string]string
    os osinterface.OS

    // Storage and indexing
    sandboxStore *sandboxstore.Store
    sandboxNameIndex *registrar.Registrar  // Ensures unique sandbox names
    containerStore *containerstore.Store
    containerNameIndex *registrar.Registrar // Ensures unique container names

    // Network management
    netPlugin map[string]cni.CNI

    // containerd client
    client *containerd.Client

    // Streaming support
    streamServer streaming.Server

    // Event monitoring
    eventMonitor *events.EventMonitor

    // Initialization flag
    initialized atomic.Bool

    // Network config monitoring
    cniNetConfMonitor map[string]*cniNetConfSyncer

    // Capabilities
    allCaps []string

    // Container events queue
    containerEventsQ eventq.EventQueue[*runtime.ContainerEventResponse]

    // Node Resource Interface
    nri *nri.API

    // Sandbox service
    sandboxService sandboxService

    // Runtime handlers and features
    runtimeHandlers map[string]*runtime.RuntimeHandler
    runtimeFeatures *runtime.RuntimeFeatures

    // Stats collection
    statsCollector *StatsCollector
}
```

**Constructor:** `NewCRIService(options *CRIServiceOptions)`

Creates a fully initialized CRI service with:
- Sandbox and container stores
- CNI network plugin initialization
- Streaming server setup
- Event monitoring
- Stats collection

### 3.3 RPC Method Implementation Examples

#### RunPodSandbox Implementation

**File:** `internal/cri/server/sandbox_run.go`

```go
func (c *criService) RunPodSandbox(ctx context.Context, r *runtime.RunPodSandboxRequest)
    (*runtime.RunPodSandboxResponse, error) {

    config := r.GetConfig()

    // 1. Generate unique ID and name
    id := util.GenerateID()
    metadata := config.GetMetadata()
    name := makeSandboxName(metadata)

    // 2. Reserve the name (prevents concurrent creation with same name)
    if err := c.sandboxNameIndex.Reserve(name, id); err != nil {
        return nil, fmt.Errorf("failed to reserve sandbox name %q: %w", name, err)
    }
    defer cleanup()

    // 3. Create lease for sandbox lifecycle
    leaseSvc := c.client.LeasesService()
    ls, lerr := leaseSvc.Create(ctx, leases.WithID(id))

    // 4. Setup network (CNI)
    // - Call network plugin to setup network namespace
    // - Allocate IP addresses for the pod

    // 5. Create sandbox container (OCI spec from config)
    // - Convert CRI PodSandboxConfig to OCI spec
    // - Create containerd container

    // 6. Start sandbox task
    // - Start the sandbox task in containerd
    // - Ensure sandbox is in ready state

    // 7. Register sandbox in store
    sandboxStore.Add(id, &Sandbox{
        ID:     id,
        Config: config,
        State:  SANDBOX_READY,
    })

    // 8. Return response
    return &runtime.RunPodSandboxResponse{
        PodSandboxId: id,
    }, nil
}
```

**Key Details:**
- Generates unique sandbox ID using `util.GenerateID()`
- Reserves sandbox name to prevent concurrent duplicates
- Creates lease for resource tracking
- Sets up network using CNI plugins
- Creates and starts sandbox task in containerd
- Stores sandbox metadata in sandboxStore
- Returns sandbox ID to caller (kubelet)

#### StopPodSandbox Implementation

**File:** `internal/cri/server/sandbox_stop.go`

```go
func (c *criService) StopPodSandbox(ctx context.Context, r *runtime.StopPodSandboxRequest)
    (*runtime.StopPodSandboxResponse, error) {

    podSandboxID := r.PodSandboxId
    gracePeriod := r.Timeout

    // 1. Lookup sandbox in store
    sandbox, err := c.sandboxStore.Get(podSandboxID)

    // 2. Stop all containers in sandbox (forced termination)
    for _, container := range c.containerStore.ListByPodID(podSandboxID) {
        c.StopContainer(ctx, container.ID, gracePeriod)
    }

    // 3. Stop sandbox task in containerd
    // - Send SIGTERM to sandbox
    // - Wait for grace period
    // - Force kill if still running

    // 4. Teardown network (CNI)
    // - Release IP addresses
    // - Cleanup network namespace

    // 5. Update sandbox state
    sandbox.State = SANDBOX_NOTREADY
    c.sandboxStore.Update(podSandboxID, sandbox)

    // 6. Idempotent: return nil even if already stopped
    return &runtime.StopPodSandboxResponse{}, nil
}
```

**Key Details:**
- Idempotent operation (safe to call multiple times)
- Forcibly terminates all containers in sandbox
- Gracefully stops sandbox with timeout
- Tears down network resources (CNI cleanup)
- Updates sandbox state without removing from store

#### RemovePodSandbox Implementation

**File:** `internal/cri/server/sandbox_remove.go`

```go
func (c *criService) RemovePodSandbox(ctx context.Context, r *runtime.RemovePodSandboxRequest)
    (*runtime.RemovePodSandboxResponse, error) {

    podSandboxID := r.PodSandboxId

    // 1. Lookup sandbox
    sandbox, err := c.sandboxStore.Get(podSandboxID)

    // 2. Must be stopped first
    if sandbox.State != SANDBOX_NOTREADY {
        return nil, fmt.Errorf("sandbox %q is still running", podSandboxID)
    }

    // 3. Delete all containers in sandbox
    for _, container := range c.containerStore.ListByPodID(podSandboxID) {
        c.RemoveContainer(ctx, container.ID)
    }

    // 4. Delete sandbox container from containerd
    // - Delete container task
    // - Delete container
    // - Delete snapshots

    // 5. Release lease
    leaseSvc := c.client.LeasesService()
    leaseSvc.Delete(ctx, leases.WithID(podSandboxID))

    // 6. Release sandbox name
    c.sandboxNameIndex.ReleaseByName(sandbox.Name)

    // 7. Remove from store
    c.sandboxStore.Delete(podSandboxID)

    // 8. Idempotent: return nil even if already removed
    return &runtime.RemovePodSandboxResponse{}, nil
}
```

**Key Details:**
- Deletes all containers before removing sandbox
- Removes containerd resources (snapshots, leases)
- Releases reserved sandbox name
- Idempotent (safe to call on already-removed sandbox)

#### CreateContainer Implementation

**File:** `internal/cri/server/container_create.go`

```go
func (c *criService) CreateContainer(ctx context.Context, r *runtime.CreateContainerRequest)
    (*runtime.CreateContainerResponse, error) {

    podSandboxID := r.PodSandboxId
    config := r.Config
    sandboxConfig := r.SandboxConfig

    // 1. Lookup parent sandbox
    sandbox, err := c.sandboxStore.Get(podSandboxID)

    // 2. Generate container ID and name
    containerID := util.GenerateID()
    containerName := makeContainerName(metadata, sandbox.Config)

    // 3. Reserve container name
    if err := c.containerNameIndex.Reserve(containerName, containerID); err != nil {
        return nil, err
    }

    // 4. Build OCI spec from CRI ContainerConfig
    // - Start with runtime's base spec
    // - Apply image config
    // - Apply container config (env, mounts, resources, etc.)
    // - Setup hostname, DNS, security context

    // 5. Create container image snapshot
    // - Pull image if needed
    // - Create diff snapshot for container layers

    // 6. Create containerd container
    container, err := c.client.Containers().Create(ctx, &containers.Container{
        ID:     containerID,
        Image:  config.Image.Image,
        Spec:   &ociSpec,
        Snapshotter: snapshotterName,
    })

    // 7. Store container metadata
    c.containerStore.Add(containerID, &Container{
        ID:            containerID,
        PodSandboxID:  podSandboxID,
        Config:        config,
        SandboxConfig: sandboxConfig,
        ImageRef:      imageID,
        State:         CONTAINER_CREATED,
    })

    // 8. Return container ID
    return &runtime.CreateContainerResponse{
        ContainerId: containerID,
    }, nil
}
```

**Key Details:**
- Container created but NOT started yet
- Generates OCI spec from CRI config
- Pulls image if not available
- Creates snapshots for container layers
- Stores metadata for later retrieval
- Actual task execution happens in StartContainer

#### StartContainer Implementation

**File:** `internal/cri/server/container_start.go`

```go
func (c *criService) StartContainer(ctx context.Context, r *runtime.StartContainerRequest)
    (*runtime.StartContainerResponse, error) {

    containerID := r.ContainerId

    // 1. Lookup container
    container, err := c.containerStore.Get(containerID)

    // 2. Create and start task
    task, err := container.New(ctx, runtime.TaskServiceClient)

    // 3. Start the task
    err = task.Start(ctx)

    // 4. Update container state
    container.State = CONTAINER_RUNNING
    c.containerStore.Update(containerID, container)

    // 5. Return response
    return &runtime.StartContainerResponse{}, nil
}
```

