    defaultConfig := criconfig.DefaultServerConfig()
    registry.Register(&plugin.Registration{
        Type: plugins.GRPCPlugin,
        ID:   "cri",
        Requires: []plugin.Type{
            plugins.CRIServicePlugin,       // Runtime service
            plugins.PodSandboxPlugin,       // Pod sandbox support
            plugins.SandboxControllerPlugin, // Sandbox controllers
            plugins.NRIApiPlugin,           // Node Resource Interface
            plugins.EventPlugin,            // Event handling
            plugins.ServicePlugin,          // Services
            plugins.LeasePlugin,            // Lease management
            plugins.SandboxStorePlugin,     // Sandbox storage
            plugins.TransferPlugin,         // Content transfer
            plugins.WarningPlugin,          // Warning service
        },
        ConfigMigration: configMigration,
        InitFn:          initCRIService,
    })
}

// Initialization function
func initCRIService(ic *plugin.InitContext) (interface{}, error) {
    // 1. Load runtime service plugin
    criRuntimePlugin, err := ic.GetByID(plugins.CRIServicePlugin, "runtime")

    // 2. Load image service plugin
    criImagePlugin, err := ic.GetByID(plugins.CRIServicePlugin, "images")

    // 3. Create containerd client
    client, err := containerd.New("",
        containerd.WithDefaultNamespace(constants.K8sContainerdNamespace),
        containerd.WithDefaultPlatform(platforms.Default()),
        containerd.WithInMemoryServices(ic),
    )

    // 4. Get sandbox controllers
    sbControllers, err := getSandboxControllers(ic)

    // 5. Create CRI service
    s, rs, err := server.NewCRIService(&server.CRIServiceOptions{
        RuntimeService:     criRuntimePlugin.(server.RuntimeService),
        ImageService:       criImagePlugin.(server.ImageService),
        StreamingConfig:    streamingConfig,
        NRI:                getNRIAPI(ic),
        Client:             client,
        SandboxControllers: sbControllers,
    })

    // 6. Wrap in gRPC server
    service := &criGRPCServer{
        RuntimeServiceServer: rs,
        ImageServiceServer:   is,
        Closer:               s,
        initializer:          s,
    }

    return service, nil
}
```

